// ── Injection function ──────────────────────────────────────────────────────

function injectSecondGradeFields(filePath, newFields) {
  const src = fs.readFileSync(filePath, 'utf8');
  // Find the unique pattern: end of second-grade section + third-grade start
  const marker = /\n    \},\n    'third-grade':/;
  const match = src.match(marker);
  if (!match) {
    throw new Error(`Could not find second-grade/third-grade boundary in ${filePath}`);
  }
  // Insert the new fields before the closing }, of the second-grade section
  const insertPos = match.index;
  const updated = src.slice(0, insertPos) + '\n' + newFields + '\n    },\n    \'third-grade\':' + src.slice(match.index + match[0].length);
  fs.writeFileSync(filePath, updated, 'utf8');
  console.log(`  Updated ${path.basename(path.dirname(filePath))}/${path.basename(filePath)}`);
}

// ── Main ─────────────────────────────────────────────────────────────────────

const base = path.join(__dirname, '..', 'frontend', 'content', 'themes');

const themes = [
  { id: 'birthday', fields: birthdayFields },
  { id: 'camping', fields: campingFields },
  { id: 'circus', fields: circusFields },
  { id: 'construction', fields: constructionFields },
  { id: 'fairy-tales', fields: fairyTalesFields },
  { id: 'pirates', fields: piratesFields },
  { id: 'robots', fields: robotsFields },
  { id: 'spring', fields: springFields },
  { id: 'summer', fields: summerFields },
  { id: 'superheroes', fields: superheroesFields },
  { id: 'transportation', fields: transportationFields },
  { id: 'travel', fields: travelFields },
];

console.log('Part 198: Enriching 12 FI second-grade sections with 7 fields each...\n');
themes.forEach((t, i) => {
  console.log(`${i + 1}. Injecting second-grade fields into ${t.id}/fi.ts...`);
  injectSecondGradeFields(path.join(base, t.id, 'fi.ts'), t.fields);
});
console.log('\nDone! All 12 FI second-grade sections enriched with 7 fields each.');
